const regexValidator = (input) => {
    // Define regex patterns for validation
    const patterns = [
        /^[A-Z]{2,5}$/,
        /^([a-z]{2,5})\1$/,
        /^\d{3}-\d{3}-\d{4}$/,
        /^[A-Za-z0-9]{10,20}$/,
        /^(?=.*[A-Z])(?=.*[!@#$%^&*])(?=.*[0-9])(?=.*[a-z]).{8,16}$/,
        /^(?!.*(?:([a-zA-Z0-9])\1\1)).{6,12}$/,
        /^[A-Za-z]+$/,
        /^(?=.*\d)(?=.*[a-z])(?=.*[A-Z])[a-zA-Z0-9]{8,}$/,
        /^(?=.*\d)(?=.*[A-Za-z])[0-9A-Za-z@#$%]{8,16}$/,
        /^(.*?)(.*?)(?!\1)(?!\2)[a-zA-Z0-9]{5,10}$/,
    ];

    // Validate input against regex patterns
    let isValid = false;
    for (const pattern of patterns) {
        if (pattern.test(input)) {
            isValid = true;
            break;
        }
    }

    return isValid;
};

// Test the regexValidator function
console.log(regexValidator("ABCD")); // true
console.log(regexValidator("abcabc")); // true
console.log(regexValidator("123-456-7890")); // true
console.log(regexValidator("aBcDEf1234")); // true
console.log(regexValidator("Password!123")); // true
console.log(regexValidator("111222")); // false
console.log(regexValidator("Hello123")); // false
console.log(regexValidator("WelcomeTo1")); // true (weird pattern)
```

In the example above, the `regexValidator` function is a complex function that applies multiple regex patterns for validation. It checks various conditions, such as matching specific letter patterns, phone number format, password requirements, and even some weird pattern validations.

